export const parseCandidatePhoneData = (phoneStr: string) => {
  if (!phoneStr) return { phone: '', disc: '', notes: '' };

  let phone = phoneStr.split('===DISC===')[0].split('===NOTES===')[0].trim();

  let notes = '';
  if (phoneStr.includes('===NOTES===')) {
    const afterNotes = phoneStr.split('===NOTES===')[1];
    notes = afterNotes.split('===DISC===')[0].trim();
  }

  let disc = '';
  if (phoneStr.includes('===DISC===')) {
    const afterDisc = phoneStr.split('===DISC===')[1];
    disc = afterDisc.split('===NOTES===')[0].trim();
  }

  return { phone, disc, notes };
};

export const serializeCandidatePhoneData = (phone: string, disc: string, notes: string) => {
  let result = phone.trim();
  if (disc.trim()) {
    result += ` ===DISC===${disc.trim()}`;
  }
  if (notes.trim()) {
    result += ` ===NOTES===${notes.trim()}`;
  }
  return result;
};

